def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        penalty = 1.0
        bonus = 1.0
        for m in range(1, 15):
            if m % 2 == 0:
                bonus *= 1.05
            else:
                penalty *= 0.95
            partial = 0.0
            for n in range(1, 7):
                temp_ratio = ratio * n / (m + 1)
                if temp_ratio < 0.3:
                    partial += (np.sin(temp_ratio * np.pi) * (m + n)) / (n + 1)
                else:
                    partial += (np.cos(temp_ratio) + np.log1p(m*n)) / (m + n)
                if (cap + m * n) % 4 == 0:
                    partial *= 1.02
                elif (cap - n * m) % 5 == 0:
                    partial *= 0.98
                for p in range(1, 4):
                    diff = cap - item * p * n
                    if diff > 0:
                        if diff % (p + 1) == 0:
                            partial += (diff ** (0.5)) / (p + n)
                        else:
                            partial -= np.log1p(abs(diff)) / (p + m)
                    else:
                        partial -= (abs(diff) ** 1.2) / (p + m + n)
            score += partial * bonus * penalty
            if m == 10:
                if ratio > 0.8:
                    score *= 1.3
                elif ratio < 0.2:
                    score *= 0.7
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * np.log1p(cap * item + 1)
        else:
            if cap > item * 4:
                priorities[i] = -score / (np.cbrt(cap) + 1)
            else:
                priorities[i] = -score / (cap + 3)
        if ratio > 0.85:
            priorities[i] *= 1.15
        elif ratio < 0.05:
            priorities[i] *= 0.75
        if cap % 7 == 0:
            priorities[i] *= 0.95
        elif cap % 11 == 0:
            priorities[i] *= 1.05
    return priorities
